498: // runWorker is the logic of the one and only worker goroutine.  We
499: // limit the number to one in order to obviate explicit
500: // synchronization around access to `cfgCtlr.mostRecentUpdates`.
501: func (cfgCtlr *configController) runWorker() {
502: 	for cfgCtlr.processNextWorkItem() {
503: 	}
504: }
