506: // processNextWorkItem works on one entry from the work queue.
507: // Only invoke this in the one and only worker goroutine.
508: func (cfgCtlr *configController) processNextWorkItem() bool {
509: 	obj, shutdown := cfgCtlr.configQueue.Get()
510: 	if shutdown {
511: 		return false
512: 	}
513: 
514: 	func(obj int) {
515: 		defer cfgCtlr.configQueue.Done(obj)
516: 		specificDelay, err := cfgCtlr.syncOne()
517: 		switch {
518: 		case err != nil:
519: 			klog.Error(err)
520: 			cfgCtlr.configQueue.AddRateLimited(obj)
521: 		case specificDelay > 0:
522: 			cfgCtlr.configQueue.AddAfter(obj, specificDelay)
523: 		default:
524: 			cfgCtlr.configQueue.Forget(obj)
525: 		}
526: 	}(obj)
527: 
528: 	return true
529: }
