628: func apply(client flowcontrolclient.FlowSchemaInterface, fsu fsStatusUpdate, asFieldManager string) error {
629: 	applyOptions := metav1.ApplyOptions{FieldManager: asFieldManager, Force: true}
630: 
631: 	// the condition field in fsStatusUpdate holds the new condition we want to update.
632: 	// TODO: this will break when we have multiple conditions for a flowschema
633: 	_, err := client.ApplyStatus(context.TODO(), toFlowSchemaApplyConfiguration(fsu), applyOptions)
634: 	return err
635: }
636: 
637: func toFlowSchemaApplyConfiguration(fsUpdate fsStatusUpdate) *flowcontrolapplyconfiguration.FlowSchemaApplyConfiguration {
638: 	condition := flowcontrolapplyconfiguration.FlowSchemaCondition().
639: 		WithType(fsUpdate.condition.Type).
640: 		WithStatus(fsUpdate.condition.Status).
641: 		WithReason(fsUpdate.condition.Reason).
642: 		WithLastTransitionTime(fsUpdate.condition.LastTransitionTime).
643: 		WithMessage(fsUpdate.condition.Message)
644: 
645: 	return flowcontrolapplyconfiguration.FlowSchema(fsUpdate.flowSchema.Name).
646: 		WithStatus(flowcontrolapplyconfiguration.FlowSchemaStatus().
647: 			WithConditions(condition),
648: 		)
649: }
