679: func (cfgCtlr *configController) lockAndDigestConfigObjects(newPLs []*flowcontrol.PriorityLevelConfiguration, newFSs []*flowcontrol.FlowSchema) []fsStatusUpdate {
680: 	cfgCtlr.lock.Lock()
681: 	defer cfgCtlr.lock.Unlock()
682: 	meal := cfgMeal{
683: 		cfgCtlr:     cfgCtlr,
684: 		newPLStates: make(map[string]*priorityLevelState),
685: 	}
686: 
687: 	meal.digestNewPLsLocked(newPLs)
688: 	meal.digestFlowSchemasLocked(newFSs)
689: 	meal.processOldPLsLocked()
690: 
691: 	// Supply missing mandatory PriorityLevelConfiguration objects
692: 	if !meal.haveExemptPL {
693: 		meal.imaginePL(fcboot.MandatoryPriorityLevelConfigurationExempt)
694: 	}
695: 	if !meal.haveCatchAllPL {
696: 		meal.imaginePL(fcboot.MandatoryPriorityLevelConfigurationCatchAll)
697: 	}
698: 
699: 	meal.finishQueueSetReconfigsLocked()
700: 
701: 	// The new config has been constructed
702: 	cfgCtlr.priorityLevelStates = meal.newPLStates
703: 	klog.V(5).InfoS("Switched to new API Priority and Fairness configuration", "maxWaitingRequests", meal.maxWaitingRequests, "maxExecutinRequests", meal.maxExecutingRequests)
704: 
705: 	metrics.GetWaitingReadonlyConcurrency().SetDenominator(float64(meal.maxWaitingRequests))
706: 	metrics.GetWaitingMutatingConcurrency().SetDenominator(float64(meal.maxWaitingRequests))
707: 	metrics.GetExecutingReadonlyConcurrency().SetDenominator(float64(meal.maxExecutingRequests))
708: 	metrics.GetExecutingMutatingConcurrency().SetDenominator(float64(meal.maxExecutingRequests))
709: 
710: 	return meal.fsStatusUpdates
711: }
