713: // Digest the new set of PriorityLevelConfiguration objects.
714: // Pretend broken ones do not exist.
715: func (meal *cfgMeal) digestNewPLsLocked(newPLs []*flowcontrol.PriorityLevelConfiguration) {
716: 	for _, pl := range newPLs {
717: 		state := meal.cfgCtlr.priorityLevelStates[pl.Name]
718: 		if state == nil {
719: 			labelValues := []string{pl.Name}
720: 			state = &priorityLevelState{
721: 				reqsGaugePair:          metrics.RatioedGaugeVecPhasedElementPair(meal.cfgCtlr.reqsGaugeVec, 1, 1, labelValues),
722: 				execSeatsObs:           meal.cfgCtlr.execSeatsGaugeVec.NewForLabelValuesSafe(0, 1, labelValues),
723: 				seatDemandIntegrator:   fq.NewNamedIntegrator(meal.cfgCtlr.clock, pl.Name),
724: 				seatDemandRatioedGauge: metrics.ApiserverSeatDemands.NewForLabelValuesSafe(0, 1, []string{pl.Name}),
725: 			}
726: 		}
727: 		qsCompleter, err := queueSetCompleterForPL(meal.cfgCtlr.queueSetFactory, state.queues,
728: 			pl, state.reqsGaugePair, state.execSeatsObs,
729: 			metrics.NewUnionGauge(state.seatDemandIntegrator, state.seatDemandRatioedGauge))
730: 		if err != nil {
731: 			klog.Warningf("Ignoring PriorityLevelConfiguration object %s because its spec (%s) is broken: %s", pl.Name, fcfmt.Fmt(pl.Spec), err)
732: 			continue
733: 		}
734: 		meal.newPLStates[pl.Name] = state
735: 		state.pl = pl
736: 		state.qsCompleter = qsCompleter
737: 		if state.quiescing { // it was undesired, but no longer
738: 			klog.V(3).Infof("Priority level %q was undesired and has become desired again", pl.Name)
739: 			state.quiescing = false
740: 		}
741: 		nominalConcurrencyShares, _, _ := plSpecCommons(state.pl)
742: 		meal.shareSum += float64(*nominalConcurrencyShares)
743: 		meal.haveExemptPL = meal.haveExemptPL || pl.Name == flowcontrol.PriorityLevelConfigurationNameExempt
744: 		meal.haveCatchAllPL = meal.haveCatchAllPL || pl.Name == flowcontrol.PriorityLevelConfigurationNameCatchAll
745: 	}
746: }
