{"content":"750: // use.  We do this before holding over old priority levels so that
751: // requests stop going to those levels and FlowSchemaStatus values
752: // reflect this.  This function also adds any missing mandatory
753: // FlowSchema objects.  The given objects must all have distinct
754: // names.
755: func (meal *cfgMeal) digestFlowSchemasLocked(newFSs []*flowcontrol.FlowSchema) {
756: 	fsSeq := make(apihelpers.FlowSchemaSequence, 0, len(newFSs))
757: 	fsMap := make(map[string]*flowcontrol.FlowSchema, len(newFSs))
758: 	var haveExemptFS, haveCatchAllFS bool
759: 	for i, fs := range newFSs {
760: 		otherFS := fsMap[fs.Name]
761: 		if otherFS != nil {
762: 			// This client is forbidden to do this.
763: 			panic(fmt.Sprintf("Given two FlowSchema objects with the same name: %s and %s", fcfmt.Fmt(otherFS), fcfmt.Fmt(fs)))
764: 		}
765: 		fsMap[fs.Name] = fs
766: 		_, goodPriorityRef := meal.newPLStates[fs.Spec.PriorityLevelConfiguration.Name]
767: 
768: 		// Ensure the object's status reflects whether its priority
769: 		// level reference is broken.
770: 		//
771: 		// TODO: consider not even trying if server is not handling
772: 		// requests yet.
773: 		meal.presyncFlowSchemaStatus(fs, meal.cfgCtlr.foundToDangling(goodPriorityRef), fs.Spec.PriorityLevelConfiguration.Name)
774: 
775: 		if !goodPriorityRef {
776: 			klog.V(6).Infof("Ignoring FlowSchema %s because of bad priority level reference %q", fs.Name, fs.Spec.PriorityLevelConfiguration.Name)
777: 			continue
778: 		}
779: 		fsSeq = append(fsSeq, newFSs[i])
780: 		haveExemptFS = haveExemptFS || fs.Name == flowcontrol.FlowSchemaNameExempt
781: 		haveCatchAllFS = haveCatchAllFS || fs.Name == flowcontrol.FlowSchemaNameCatchAll
782: 	}
783: 	// sort into the order to be used for matching
784: 	sort.Sort(fsSeq)
785: 
786: 	// Supply missing mandatory FlowSchemas, in correct position
787: 	if !haveExemptFS {
788: 		fsSeq = append(apihelpers.FlowSchemaSequence{fcboot.MandatoryFlowSchemaExempt}, fsSeq...)
789: 	}
790: 	if !haveCatchAllFS {
791: 		fsSeq = append(fsSeq, fcboot.MandatoryFlowSchemaCatchAll)
792: 	}
793: 
794: 	meal.cfgCtlr.flowSchemas = fsSeq
795: 	klogV := klog.V(5)
796: 	if klogV.Enabled() {
797: 		for _, fs := range fsSeq {
798: 			klogV.Infof("Using FlowSchema %s", fcfmt.Fmt(fs))
799: 		}
800: 	}
801: }
802: 
803: // Consider all the priority levels in the previous configuration.
804: // Keep the ones that are in the new config, supply mandatory
805: // behavior, or are still busy; for the rest: drop it if it has no
806: // queues, otherwise start the quiescing process if that has not
807: // already been started.
808: func (meal *cfgMeal) processOldPLsLocked() {
809: 	for plName, plState := range meal.cfgCtlr.priorityLevelStates {
810: 		if meal.newPLStates[plName] != nil {
811: 			// Still desired and already updated
812: 			continue
813: 		}
814: 		if plName == flowcontrol.PriorityLevelConfigurationNameExempt && !meal.haveExemptPL || plName == flowcontrol.PriorityLevelConfigurationNameCatchAll && !meal.haveCatchAllPL {
815: 			// BTW, we know the Spec has not changed what is says about queuing because the
816: 			// mandatory objects have immutable Specs as far as queuing is concerned.
817: 			klog.V(3).Infof("Retaining mandatory priority level %q despite lack of API object", plName)
818: 		} else {
819: 			if plState.numPending == 0 && plState.queues.IsIdle() {
820: 				// The QueueSet is done
821: 				// draining and no use is coming from another
822: 				// goroutine
823: 				klog.V(3).Infof("Removing undesired priority level %q, Type=%v", plName, plState.pl.Spec.Type)
824: 				meal.cfgCtlr.MaxSeatsTracker.ForgetPriorityLevel(plName)
825: 				continue
826: 			}
827: 			if !plState.quiescing {
828: 				klog.V(3).Infof("Priority level %q became undesired", plName)
829: 				plState.quiescing = true
830: 			}
831: 		}
832: 		var err error
833: 		plState.qsCompleter, err = queueSetCompleterForPL(meal.cfgCtlr.queueSetFactory, plState.queues,
834: 			plState.pl, plState.reqsGaugePair, plState.execSeatsObs,
835: 			metrics.NewUnionGauge(plState.seatDemandIntegrator, plState.seatDemandRatioedGauge))
836: 		if err != nil {
837: 			// This can not happen because queueSetCompleterForPL already approved this config
838: 			panic(fmt.Sprintf("%s from name=%q spec=%s", err, plName, fcfmt.Fmt(plState.pl.Spec)))
839: 		}
840: 		// We deliberately include the lingering priority levels
841: 		// here so that their queues get some concurrency and they
842: 		// continue to drain.  During this interim a lingering
843: 		// priority level continues to get a concurrency
844: 		// allocation determined by all the share values in the
845: 		// regular way.
846: 		nominalConcurrencyShares, _, _ := plSpecCommons(plState.pl)
847: 		meal.shareSum += float64(*nominalConcurrencyShares)
848: 		meal.haveExemptPL = meal.haveExemptPL || plName == flowcontrol.PriorityLevelConfigurationNameExempt
849: 		meal.haveCatchAllPL = meal.haveCatchAllPL || plName == flowcontrol.PriorityLevelConfigurationNameCatchAll
850: 		meal.newPLStates[plName] = plState
851: 	}
852: }
