854: // For all the priority levels of the new config, divide up the
855: // server's total concurrency limit among them and create/update their
856: // QueueSets.
857: func (meal *cfgMeal) finishQueueSetReconfigsLocked() {
858: 	for plName, plState := range meal.newPLStates {
859: 		nominalConcurrencyShares, lendablePercent, borrowingLimitPercent := plSpecCommons(plState.pl)
860: 		// The use of math.Ceil here means that the results might sum
861: 		// to a little more than serverConcurrencyLimit but the
862: 		// difference will be negligible.
863: 		concurrencyLimit := int(math.Ceil(float64(meal.cfgCtlr.serverConcurrencyLimit) * float64(*nominalConcurrencyShares) / meal.shareSum))
864: 		var lendableCL, borrowingCL int
865: 		if lendablePercent != nil {
866: 			lendableCL = int(math.Round(float64(concurrencyLimit) * float64(*lendablePercent) / 100))
867: 		}
868: 		if borrowingLimitPercent != nil {
869: 			borrowingCL = int(math.Round(float64(concurrencyLimit) * float64(*borrowingLimitPercent) / 100))
870: 		} else {
871: 			borrowingCL = meal.cfgCtlr.serverConcurrencyLimit
872: 		}
873: 
874: 		metrics.SetPriorityLevelConfiguration(plName, concurrencyLimit, concurrencyLimit-lendableCL, concurrencyLimit+borrowingCL)
875: 		cfgChanged := plState.nominalCL != concurrencyLimit || plState.minCL != concurrencyLimit-lendableCL || plState.maxCL != concurrencyLimit+borrowingCL
876: 		plState.nominalCL = concurrencyLimit
877: 		plState.minCL = concurrencyLimit - lendableCL
878: 		plState.maxCL = concurrencyLimit + borrowingCL
879: 		meal.maxExecutingRequests += concurrencyLimit
880: 		if limited := plState.pl.Spec.Limited; limited != nil {
881: 			if qCfg := limited.LimitResponse.Queuing; qCfg != nil {
882: 				meal.maxWaitingRequests += int(qCfg.Queues * qCfg.QueueLengthLimit)
883: 
884: 				// Max seats allocatable from work estimator is calculated as MAX(1, MIN(0.15 * nominalCL, nominalCL/handSize)).
885: 				// This is to keep max seats relative to total available concurrency with a minimum value of 1.
886: 				// 15% of nominal concurrency was chosen since it preserved the previous max seats of 10 for default priority levels
887: 				// when using apiserver's default total server concurrency of 600 (--max-requests-inflight=400, --max-mutating-requests-inflight=200).
888: 				// This ensures that clusters with relatively high inflight requests will continue to use a max seats of 10
889: 				// while clusters with lower inflight requests will use max seats no greater than nominalCL/handSize.
890: 				// Calculated max seats can return arbitrarily high values but work estimator currently limits max seats at 10.
891: 				handSize := plState.pl.Spec.Limited.LimitResponse.Queuing.HandSize
892: 				maxSeats := uint64(math.Max(1, math.Min(math.Ceil(float64(concurrencyLimit)*priorityLevelMaxSeatsPercent), float64(int32(concurrencyLimit)/handSize))))
893: 				meal.cfgCtlr.MaxSeatsTracker.SetMaxSeats(plName, maxSeats)
894: 			}
895: 		}
896: 		if plState.queues == nil {
897: 			initialCL := concurrencyLimit - lendableCL/2
898: 			klog.V(2).Infof("Introducing queues for priority level %q: config=%s, nominalCL=%d, lendableCL=%d, borrowingCL=%d, currentCL=%d, quiescing=%v (shares=%v, shareSum=%v)", plName, fcfmt.Fmt(plState.pl.Spec), concurrencyLimit, lendableCL, borrowingCL, initialCL, plState.quiescing, nominalConcurrencyShares, meal.shareSum)
899: 			plState.seatDemandStats = seatDemandStats{}
900: 			plState.currentCL = initialCL
901: 		} else {
902: 			logLevel := klog.Level(5)
903: 			if cfgChanged {
904: 				logLevel = 2
905: 			}
906: 			klog.V(logLevel).Infof("Retaining queues for priority level %q: config=%s, nominalCL=%d, lendableCL=%d, borrowingCL=%d, currentCL=%d, quiescing=%v, numPending=%d (shares=%v, shareSum=%v)", plName, fcfmt.Fmt(plState.pl.Spec), concurrencyLimit, lendableCL, borrowingCL, plState.currentCL, plState.quiescing, plState.numPending, nominalConcurrencyShares, meal.shareSum)
907: 		}
908: 	}
909: 	meal.cfgCtlr.nominalCLSum = meal.maxExecutingRequests
910: 	meal.cfgCtlr.updateBorrowingLocked(false, meal.newPLStates)
911: }
