913: // queueSetCompleterForPL returns an appropriate QueueSetCompleter for the
914: // given priority level configuration.  Returns nil and an error if the given
915: // object is malformed in a way that is a problem for this package.
916: func queueSetCompleterForPL(qsf fq.QueueSetFactory, queues fq.QueueSet, pl *flowcontrol.PriorityLevelConfiguration, reqsIntPair metrics.RatioedGaugePair, execSeatsObs metrics.RatioedGauge, seatDemandGauge metrics.Gauge) (fq.QueueSetCompleter, error) {
917: 	if (pl.Spec.Type == flowcontrol.PriorityLevelEnablementLimited) != (pl.Spec.Limited != nil) {
918: 		return nil, errors.New("broken union structure at the top, for Limited")
919: 	}
920: 	if (pl.Spec.Type == flowcontrol.PriorityLevelEnablementExempt) != (pl.Spec.Exempt != nil) {
921: 		return nil, errors.New("broken union structure at the top, for Exempt")
922: 	}
923: 	if (pl.Spec.Type == flowcontrol.PriorityLevelEnablementExempt) != (pl.Name == flowcontrol.PriorityLevelConfigurationNameExempt) {
924: 		// This package does not attempt to cope with a priority level dynamically switching between exempt and not.
925: 		return nil, errors.New("non-alignment between name and type")
926: 	}
927: 	qcQS := fq.QueuingConfig{Name: pl.Name}
928: 	if pl.Spec.Limited != nil {
929: 		if (pl.Spec.Limited.LimitResponse.Type == flowcontrol.LimitResponseTypeReject) != (pl.Spec.Limited.LimitResponse.Queuing == nil) {
930: 			return nil, errors.New("broken union structure for limit response")
931: 		}
932: 		qcAPI := pl.Spec.Limited.LimitResponse.Queuing
933: 		if qcAPI != nil {
934: 			qcQS = fq.QueuingConfig{Name: pl.Name,
935: 				DesiredNumQueues: int(qcAPI.Queues),
936: 				QueueLengthLimit: int(qcAPI.QueueLengthLimit),
937: 				HandSize:         int(qcAPI.HandSize),
938: 			}
939: 		}
940: 	} else {
941: 		qcQS = fq.QueuingConfig{Name: pl.Name, DesiredNumQueues: -1}
942: 	}
943: 	var qsc fq.QueueSetCompleter
944: 	var err error
945: 	if queues != nil {
946: 		qsc, err = queues.BeginConfigChange(qcQS)
947: 	} else {
948: 		qsc, err = qsf.BeginConstruction(qcQS, reqsIntPair, execSeatsObs, seatDemandGauge)
949: 	}
950: 	if err != nil {
951: 		err = fmt.Errorf("priority level %q has QueuingConfiguration %#+v, which is invalid: %w", pl.Name, qcQS, err)
952: 	}
953: 	return qsc, err
954: }
