956: func (meal *cfgMeal) presyncFlowSchemaStatus(fs *flowcontrol.FlowSchema, isDangling bool, plName string) {
957: 	danglingCondition := apihelpers.GetFlowSchemaConditionByType(fs, flowcontrol.FlowSchemaConditionDangling)
958: 	if danglingCondition == nil {
959: 		danglingCondition = &flowcontrol.FlowSchemaCondition{
960: 			Type: flowcontrol.FlowSchemaConditionDangling,
961: 		}
962: 	}
963: 	desiredStatus := flowcontrol.ConditionFalse
964: 	var desiredReason, desiredMessage string
965: 	if isDangling {
966: 		desiredStatus = flowcontrol.ConditionTrue
967: 		desiredReason = "NotFound"
968: 		desiredMessage = fmt.Sprintf("This FlowSchema references the PriorityLevelConfiguration object named %q but there is no such object", plName)
969: 	} else {
970: 		desiredReason = "Found"
971: 		desiredMessage = fmt.Sprintf("This FlowSchema references the PriorityLevelConfiguration object named %q and it exists", plName)
972: 	}
973: 	if danglingCondition.Status == desiredStatus && danglingCondition.Reason == desiredReason && danglingCondition.Message == desiredMessage {
974: 		return
975: 	}
976: 	now := meal.cfgCtlr.clock.Now()
977: 	meal.fsStatusUpdates = append(meal.fsStatusUpdates, fsStatusUpdate{
978: 		flowSchema: fs,
979: 		condition: flowcontrol.FlowSchemaCondition{
980: 			Type:               flowcontrol.FlowSchemaConditionDangling,
981: 			Status:             desiredStatus,
982: 			LastTransitionTime: metav1.NewTime(now),
983: 			Reason:             desiredReason,
984: 			Message:            desiredMessage,
985: 		},
986: 		oldValue: *danglingCondition})
987: }
