989: // imaginePL adds a priority level based on one of the mandatory ones
990: // that does not actually exist (right now) as a real API object.
991: func (meal *cfgMeal) imaginePL(proto *flowcontrol.PriorityLevelConfiguration) {
992: 	klog.V(3).Infof("No %s PriorityLevelConfiguration found, imagining one", proto.Name)
993: 	labelValues := []string{proto.Name}
994: 	reqsGaugePair := metrics.RatioedGaugeVecPhasedElementPair(meal.cfgCtlr.reqsGaugeVec, 1, 1, labelValues)
995: 	execSeatsObs := meal.cfgCtlr.execSeatsGaugeVec.NewForLabelValuesSafe(0, 1, labelValues)
996: 	seatDemandIntegrator := fq.NewNamedIntegrator(meal.cfgCtlr.clock, proto.Name)
997: 	seatDemandRatioedGauge := metrics.ApiserverSeatDemands.NewForLabelValuesSafe(0, 1, []string{proto.Name})
998: 	qsCompleter, err := queueSetCompleterForPL(meal.cfgCtlr.queueSetFactory, nil, proto, reqsGaugePair,
999: 		execSeatsObs, metrics.NewUnionGauge(seatDemandIntegrator, seatDemandRatioedGauge))
1000: 	if err != nil {
1001: 		// This can not happen because proto is one of the mandatory
1002: 		// objects and these are not erroneous
1003: 		panic(err)
1004: 	}
1005: 	meal.newPLStates[proto.Name] = &priorityLevelState{
1006: 		pl:                     proto,
1007: 		qsCompleter:            qsCompleter,
1008: 		reqsGaugePair:          reqsGaugePair,
1009: 		execSeatsObs:           execSeatsObs,
1010: 		seatDemandIntegrator:   seatDemandIntegrator,
1011: 		seatDemandRatioedGauge: seatDemandRatioedGauge,
1012: 	}
1013: 	nominalConcurrencyShares, _, _ := plSpecCommons(proto)
1014: 	meal.shareSum += float64(*nominalConcurrencyShares)
1015: }
