1115: // computeFlowDistinguisher extracts the flow distinguisher according to the given method
1116: func computeFlowDistinguisher(rd RequestDigest, method *flowcontrol.FlowDistinguisherMethod) string {
1117: 	if method == nil {
1118: 		return ""
1119: 	}
1120: 	switch method.Type {
1121: 	case flowcontrol.FlowDistinguisherMethodByUserType:
1122: 		return rd.User.GetName()
1123: 	case flowcontrol.FlowDistinguisherMethodByNamespaceType:
1124: 		return rd.RequestInfo.Namespace
1125: 	default:
1126: 		// this line shall never reach
1127: 		panic("invalid flow-distinguisher method")
1128: 	}
1129: }
