1131: func hashFlowID(fsName, fDistinguisher string) uint64 {
1132: 	hash := sha256.New()
1133: 	var sep = [1]byte{0}
1134: 	hash.Write([]byte(fsName))
1135: 	hash.Write(sep[:])
1136: 	hash.Write([]byte(fDistinguisher))
1137: 	var sum [32]byte
1138: 	hash.Sum(sum[:0])
1139: 	return binary.LittleEndian.Uint64(sum[:8])
1140: }
