1142: func relDiff(x, y float64) float64 {
1143: 	diff := math.Abs(x - y)
1144: 	den := math.Max(math.Abs(x), math.Abs(y))
1145: 	if den == 0 {
1146: 		return 0
1147: 	}
1148: 	return diff / den
1149: }
