1151: // plSpecCommons returns the (NominalConcurrencyShares, LendablePercent, BorrowingLimitPercent) of the given priority level config
1152: func plSpecCommons(pl *flowcontrol.PriorityLevelConfiguration) (*int32, *int32, *int32) {
1153: 	if limiter := pl.Spec.Limited; limiter != nil {
1154: 		return limiter.NominalConcurrencyShares, limiter.LendablePercent, limiter.BorrowingLimitPercent
1155: 	}
1156: 	limiter := pl.Spec.Exempt
1157: 	var nominalConcurrencyShares int32
1158: 	if limiter.NominalConcurrencyShares != nil {
1159: 		nominalConcurrencyShares = *limiter.NominalConcurrencyShares
1160: 	}
1161: 	return &nominalConcurrencyShares, limiter.LendablePercent, nil
1162: }
